--Script that uses system views to retrieve the list of user tables, their estimated row counts, and their total space usage (including data and indexes) in Gigabytes.
--This script uses sys.dm_db_partition_stats which provides a good balance between accuracy and performance, as it reads metadata rather than scanning the tables directly.
-- ====================================================================================
-- Author:      [Generated by AI - Review Recommended]
-- Create date: [Current Date]
-- Description: Lists all user tables in the current database,
--              their total row count, and their total size (data + indexes) in GB.
-- Database:    Run this script in the context of the database you want to query.
-- Notes:
--   - Row counts are based on metadata and might not be 100% precise,
--     especially after many modifications without statistics updates.
--   - Size includes data pages, index pages, LOB pages, etc. associated
--     with the table. It represents the space *used*.
--   - Filters out Microsoft-shipped objects.
-- ====================================================================================

-- Use a CTE to calculate row counts (summing across partitions, specifically for heap/clustered index)
WITH TableRowCounts AS (
    SELECT
        ps.object_id,
        SUM(ps.row_count) AS TotalRowCount
    FROM
        sys.dm_db_partition_stats ps
    WHERE
        ps.index_id < 2 -- 0 = Heap, 1 = Clustered Index (these store the actual table rows)
    GROUP BY
        ps.object_id
),
-- Use a CTE to calculate total used pages (summing across all partitions and indexes for the table)
TableSpaceUsage AS (
    SELECT
        ps.object_id,
        SUM(ps.used_page_count) AS TotalUsedPages
    FROM
        sys.dm_db_partition_stats ps
    GROUP BY
        ps.object_id
)
-- Final SELECT combining table info, row counts, and space usage
SELECT
    s.name AS SchemaName,
    t.name AS TableName,
    ISNULL(trc.TotalRowCount, 0) AS RecordCount, -- Display 0 if no rows found in stats
    -- Calculate size in GB (1 page = 8 KB)
    CAST( (ISNULL(tsu.TotalUsedPages, 0) * 8.0 / 1024.0 / 1024.0) AS DECIMAL(18, 4) ) AS TotalSizeGB
FROM
    sys.tables t
INNER JOIN
    sys.schemas s ON t.schema_id = s.schema_id
LEFT JOIN
    TableRowCounts trc ON t.object_id = trc.object_id
LEFT JOIN
    TableSpaceUsage tsu ON t.object_id = tsu.object_id
WHERE
    t.type = 'U' -- User table
    AND t.is_ms_shipped = 0 -- Exclude Microsoft-shipped tables (e.g., diagram tables)
ORDER BY
    TotalSizeGB DESC, -- Show largest tables first
    SchemaName ASC,
    TableName ASC;

